mapper.select:
SELECT code
FROM test_team
where id = #{deptId}

mapper.update:
update test_entrusted_info
set state=#{state}
where id = #{entrustmentId}

update test_task
set report_complete =2
WHERE entrustment_id = #{entrustmentId}

mapper.select:
SELECT t1.id, t1.task_code code, t1.orderer, DATE_FORMAT(t1.order_time, '%Y-%m-%d') order_time, DATE_FORMAT(t1.required_completion_time, '%Y-%m-%d') required_completion_time, t1.task_price , t2.sampling_method, t2.check_purpose, t2.present_information, t2.file_url, t2.seal_type, t3.sample_id, t4.sample_name, t4.alias_name, t4.product_id, t4.sample_code, t4.specs, t4.batch_number, t4.generation, t4.sample_groups, t4.quantity_per_group, t4.sample_origin, t4.manufacturer, t4.received_date, t4.inspector, t4.sample_requirement, t4.outward, t4.picture, t4.sample_quantity, t4.alias_name, t4.sample_remark, t4.sample_type, t5.check_item_id, t5.check_item_name, t5.method_id, t7.name, t5.standard_id, CONCAT(t6.code, '《', t6.`name`, '》') standard_name, t5.times, t5.unit_price, t5.id AS itemId, t5.state AS state, t5.origin_url AS originUrl, t5.opinion FROM test_task t1 LEFT JOIN test_entrusted_info t2 ON t1.entrustment_id = t2.id LEFT JOIN test_entrusted_sample_details_rel t3 ON t2.id = t3.entrustment_id LEFT JOIN test_sample t4 ON t3.sample_id = t4.id LEFT JOIN test_entrusted_sample_checkitem_rel t5 ON t1.entrustment_id = t5.entrust_id LEFT JOIN test_team as t9 ON t9.id = t5.dept_id AND t4.id = t5.sample_id LEFT JOIN test_standard_file t6 ON t5.standard_id = t6.id LEFT JOIN test_method t7 ON t5.method_id = t7.id left join test_product_item t8 on t5.check_item_id = t8.check_item_id where t1.id = #{taskId} and t5.task_id = #{taskId}
and t9.id in
#{id}
AND t5.unit_price is not null

update.foreach:
UPDATE test_task
inspector=#{item.inspector}, recorder=#{item.recorder}, report_producer=#{item.reportProducer}, reviewer=#{item.reviewer}, sample_receiving_time=#{item.sampleReceivingTime}, sampler=#{item.sampler}, receiver=#{item.receiver}, state=#{item.state}, receive_time=#{item.receiveTime},
where id = #{item.id}

mapper.select:
SELECT t3.NAME AS label, t3.user_id AS VALUE FROM test_team as t1 LEFT JOIN test_technicist as t2 ON t1.id = t2.team_id LEFT JOIN sys_user as t3 ON t3.user_id = t2.user_id WHERE t1.id in
#{id}
and t3.name is not NULL and t2.del_flag = 0

SELECT state
FROM test_task
WHERE id = #{id}

mapper.update:
update test_task
set sampler               = #{sampler,jdbcType=INTEGER},
    sample_receiving_time = #{sampleReceivingTime,jdbcType=TIMESTAMP},
    state                 = #{state,jdbcType=INTEGER},
    sample_state_description = #{sampleStateDescription}
where id = #{taskId,jdbcType=BIGINT}

mapper.select:
SELECT NAME
FROM test_original_record_template
WHERE check_item_id = #{checkItemId}

mapper.update:
update test_entrusted_sample_checkitem_rel
set origin_url   = #{originalUrl,jdbcType=VARCHAR},
    file_url_str = #{fileUrlStr,jdbcType=VARCHAR},
    item_file_name = #{fileName,jdbcType=VARCHAR}

where entrust_id = #{entrustId,jdbcType=BIGINT}
  and sample_id = #{sampleId,jdbcType=INTEGER}
  and check_item_id = #{checkItemId,jdbcType=INTEGER}

update test_entrusted_sample_checkitem_rel
set state   = #{state,jdbcType=INTEGER},
    opinion = #{opinion}
where id = #{itemId,jdbcType=INTEGER}

update test_task
inspector=#{inspector}, recorder=#{recorder}, reviewer=#{reviewer}, report_producer=#{reportProducer}, sample_receiving_time=#{sampleReceivingTime}, sample_state_description=#{sampleStateDescription}, sampler=#{sampler},
where id = #{taskId,jdbcType=INTEGER}

update test_task
set report_complete       = #{status,jdbcType=INTEGER}
where id = #{taskId,jdbcType=INTEGER}

update.foreach:
update test_entrusted_sample_checkitem_rel

    dept_id = ${item.deptId},
    distribution_date = current_timestamp(),
    task_id = ${item.taskId}

where id = ${item.id}

update test_task

    issue_report = #{item.issueReport}

where entrustment_id = #{item.entrustmentId} and dept_id = #{item.deptId}

mapper.select:
select count(*) FROM test_task WHERE state =#{state}
and dept_id in
#{id}
